import{_ as o,a as d,ai as c,o as i}from"./chunks/framework.Dc1yMVMM.js";const h=JSON.parse('{"title":"PC 项目困/难点总结","description":"","frontmatter":{},"headers":[],"relativePath":"workLog/work_project.md","filePath":"workLog/work_project.md","lastUpdated":1772591460000}'),t={name:"workLog/work_project.md"};function l(r,e,a,n,s,p){return i(),d("div",null,e[0]||(e[0]=[c('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /grady/workLog/work_project.md for this page in Markdown format</div><h1 id="pc-项目困-难点总结" tabindex="-1">PC 项目困/难点总结 <a class="header-anchor" href="#pc-项目困-难点总结" aria-label="Permalink to &quot;PC 项目困/难点总结&quot;">​</a></h1><blockquote><p>适用于面试准备，提炼技术难点与解决方案</p></blockquote><hr><h2 id="一、项目概览" tabindex="-1">一、项目概览 <a class="header-anchor" href="#一、项目概览" aria-label="Permalink to &quot;一、项目概览&quot;">​</a></h2><ul><li><strong>项目名称</strong>：云 DMS（经销商管理系统）</li><li><strong>技术栈</strong>：Vue 2.x + Vuex + Vue Router + Element UI + Axios + Webpack 4</li><li><strong>业务领域</strong>：汽车经销商售后管理（维修、索赔、配件、结算、客户等）</li><li><strong>规模</strong>：2000+ 前端文件，多微服务后端对接</li></ul><hr><h2 id="二、核心技术难点" tabindex="-1">二、核心技术难点 <a class="header-anchor" href="#二、核心技术难点" aria-label="Permalink to &quot;二、核心技术难点&quot;">​</a></h2><h3 id="_1-权限与认证体系" tabindex="-1">1. 权限与认证体系 <a class="header-anchor" href="#_1-权限与认证体系" aria-label="Permalink to &quot;1. 权限与认证体系&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><strong>多级权限</strong>：菜单级 + 页面级 + 按钮级（<code>authList</code> / <code>authMark</code>）权限控制</li><li><strong>多种登录方式</strong>：OAuth2 授权码模式、DOS Token、API 直连（<code>getTokenByApi</code>）</li><li><strong>白名单管理</strong>：<code>whiteList</code>（免登录）、<code>whiteAuth</code>（免权限）、<code>whiteSite</code>（内网免登录）</li><li><strong>SSO 集成</strong>：与 Dealer Portal 单点登录对接，需处理 <code>code</code> 换取 <code>token</code>、重定向等</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>router.beforeEach</code> 中统一鉴权，未登录则拉取 navList，无权限跳 404</li><li><code>formateMenu</code> 递归扁平化树形菜单，用于路径权限校验</li><li><code>MultiuseButton</code> 通过 <code>authList.includes(authMark)</code> 控制按钮显隐</li></ul><hr><h3 id="_2-api-签名与安全" tabindex="-1">2. API 签名与安全 <a class="header-anchor" href="#_2-api-签名与安全" aria-label="Permalink to &quot;2. API 签名与安全&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>所有请求需携带 <strong>MD5 签名</strong>（<code>signMd5Utils</code>）</li><li>签名规则：<code>md5(JSON.stringify(升序参数) + secret_key).toUpperCase()</code></li><li><code>secret_key</code> 由 <code>sessionStorage.appIdKey</code> 经 DES 解密得到</li><li>GET/POST/DELETE 参数处理方式不同（URL 参数、body、数组序列化）</li><li>需兼容 <code>|</code> 分隔的日期范围等特殊参数</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>fetchApi.post/get/put/delete</code> 统一封装，自动拼 <code>sign</code>、<code>timestamp</code></li><li><code>urlToJson</code> 分离需签名参数与直接拼接的 <code>originStringQuery</code></li><li><code>signMd5Utils.getSign</code> 支持数组参数 <code>arrayString</code> 序列化</li></ul><hr><h3 id="_3-动态菜单与路由管理" tabindex="-1">3. 动态菜单与路由管理 <a class="header-anchor" href="#_3-动态菜单与路由管理" aria-label="Permalink to &quot;3. 动态菜单与路由管理&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>菜单由后端接口按 <code>roleId</code> 返回，需与本地 <code>menu.js</code> 路由映射</li><li>多级菜单递归渲染（<code>menuTree.js</code> 中 <code>createMenuTree</code>）</li><li>图标、<code>hideInMenu</code> 等属性需从路由表 <code>deepFind</code> 补齐</li><li>支持外链菜单（<code>/^https?:\\/\\//.test(key)</code>）</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>deepMenu</code> 将接口数据转为前端菜单结构</li><li><code>formateNavList</code> 与 <code>routesMap</code> 匹配，补全 <code>icon</code>、<code>hideInMenu</code></li><li>JSX 渲染 <code>el-submenu</code> / <code>el-menu-item</code>，递归处理 <code>children</code></li></ul><hr><h3 id="_4-keepalive-与多-tab-缓存" tabindex="-1">4. KeepAlive 与多 Tab 缓存 <a class="header-anchor" href="#_4-keepalive-与多-tab-缓存" aria-label="Permalink to &quot;4. KeepAlive 与多 Tab 缓存&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>头部 Tab 需缓存页面状态，但存在 <code>maxCacheNum: 10</code> 限制</li><li><code>keep-alive :include</code> 需动态维护 <code>cachedNames</code>（组件名列表）</li><li>关闭 Tab 时要 <code>removeKeepAliveNames</code>，否则内存泄漏</li><li><strong>Iframe 页面</strong>需单独管理 <code>iframeComponentsArr</code>，支持动态注册、<code>v-show</code> 切换</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>MultiTab</code> 监听 <code>$route</code>，对 <code>meta.keepAlive</code> 的页面调用 <code>addKeepAliveNames</code></li><li><code>RouteView</code> 中 <code>cachedNames = [&#39;RouteView&#39;, ...keepAliveNames.map(x =&gt; x.value)]</code></li><li>超限时 <code>Notification.warning</code> 提示，并 <code>next(false)</code> 阻止跳转</li></ul><hr><h3 id="_5-虚拟滚动组件-virtualscroll" tabindex="-1">5. 虚拟滚动组件（VirtualScroll） <a class="header-anchor" href="#_5-虚拟滚动组件-virtualscroll" aria-label="Permalink to &quot;5. 虚拟滚动组件（VirtualScroll）&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>自研虚拟滚动，支持 <strong>固定行高</strong>（<code>itemSize</code>）与 <strong>动态行高</strong>（<code>sizeField</code> / <code>minItemSize</code>）</li><li>支持垂直/水平方向、<code>pageMode</code>（基于文档滚动）</li><li>使用 <code>pool</code> 复用 DOM、<code>$_views</code> / <code>$_unusedViews</code> 管理视图实例</li><li><code>buffer</code> 预渲染区域、<code>scrollToItem</code> / <code>scrollToPosition</code> 等能力</li></ul><p><strong>实现要点</strong>：</p><ul><li>通过 <code>sizes</code> 累加计算每项位置，<code>updateVisibleItems</code> 决定可见项</li><li><code>will-change: transform</code> + <code>translateY/X</code> 优化渲染</li><li><code>DynamicScroll</code> 支持 <code>getItemSize</code> 回调，适配高度不定的场景</li></ul><hr><h3 id="_6-复杂表格组件-basetable" tabindex="-1">6. 复杂表格组件（BaseTable） <a class="header-anchor" href="#_6-复杂表格组件-basetable" aria-label="Permalink to &quot;6. 复杂表格组件（BaseTable）&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><code>pageTable.vue</code> 2000+ 行，集成筛选、排序、分页、导出、列过滤</li><li>支持服务端排序（<code>isServerSorter</code>）、服务端筛选（<code>isServerFilter</code>）</li><li>多数据源形态：<code>dataSource</code> 为数组或 <code>{ items, total }</code></li><li>列配置复杂：<code>columnsRef</code>、<code>rowstyles</code>、<code>cellstyles</code>、<code>selectionType</code> 等</li><li>需与 <code>TopFilter</code>、<code>ColumnFilter</code>、<code>ExportExcel</code>、<code>Pagination</code> 等子组件联动</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>mergeProps</code>、<code>getOptionProps</code> 统一处理 props 透传</li><li><code>fetchapi</code> 统一封装请求，支持 <code>params</code>、<code>uidkey</code>、<code>datakey</code> 适配不同接口</li><li>支持 <code>defaultSelections</code> 预选、<code>selectionType: single|multiple</code></li></ul><hr><h3 id="_7-按需加载与懒加载-tab" tabindex="-1">7. 按需加载与懒加载 Tab <a class="header-anchor" href="#_7-按需加载与懒加载-tab" aria-label="Permalink to &quot;7. 按需加载与懒加载 Tab&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><code>LazyLoadTab</code> 通过 <code>require([</code>@/pages/${path}<code>], resolve)</code> 动态加载 Tab 内容</li><li>需解决 <code>path</code> 与组件名的映射（<code>tabMenus</code> 中 <code>title</code> 对应路径）</li><li><code>destroyOnClose</code> 控制 Tab 切换时是否销毁子组件</li><li>非当前 Tab 不渲染（<code>lazy</code>），减少首屏开销</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>loadComponent</code> 在 <code>activeName</code> 变化时注册组件</li><li><code>createTabPanel</code> 中用 <code>h(this.$options.components[x.title], ...)</code> 渲染</li><li><code>keep-alive</code> 包裹或按需 <code>isCurrent ? component : null</code></li></ul><hr><h3 id="_8-构建与性能优化" tabindex="-1">8. 构建与性能优化 <a class="header-anchor" href="#_8-构建与性能优化" aria-label="Permalink to &quot;8. 构建与性能优化&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>项目体积大，需 <code>--max-old-space-size=8192</code> 避免 Node 内存溢出</li><li>多微服务导致依赖分散，需合理的 <code>splitChunks</code> 策略</li><li><code>element-ui</code> 单独拆包（<code>app-elementUI</code>）、公共组件拆包（<code>app-commons</code>）</li><li><code>maxSize: 9000000</code> 控制单 chunk 大小，<code>maxInitialRequests: 4</code> 控制初始请求数</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>splitChunks.cacheGroups</code> 区分 libs、elementUI、commons</li><li><code>chunkFilename</code> 使用 <code>[chunkhash:8]</code> 利于缓存</li><li>开发环境 <code>cheap-source-map</code>，生产可关闭 <code>productionSourceMap</code></li></ul><hr><h3 id="_9-第三方-iframe-集成" tabindex="-1">9. 第三方 Iframe 集成 <a class="header-anchor" href="#_9-第三方-iframe-集成" aria-label="Permalink to &quot;9. 第三方 Iframe 集成&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>多个第三方系统（订购、VMS、ETKA 等）通过 iframe 嵌入</li><li>URL 需动态拼接：<code>token</code>、<code>userId</code>、<code>pagetype</code> 等，部分需 MD5 加密</li><li><code>postMessage</code> 与 iframe 内页面通信（如 <code>partEtkaInfo</code> 传 <code>sstCode</code>）</li><li>需与 <code>keep-alive</code>、Tab 关闭逻辑配合，避免 iframe 残留</li><li>iframe 高度需根据布局动态计算（<code>footer - top</code>）</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>getUrl</code> 中 <code>queryOEMDefaultParaValueByCode</code> 获取基础 URL</li><li>Token 格式：<code>userId#timestamp#DMS#md5(secret)</code> 等</li><li><code>RouteView</code> 中 <code>iframeComponentsArr</code>、<code>hasOpenComponentsArr</code> 控制 iframe 组件的注册与显示</li></ul><hr><h3 id="_10-防重复提交与业务校验" tabindex="-1">10. 防重复提交与业务校验 <a class="header-anchor" href="#_10-防重复提交与业务校验" aria-label="Permalink to &quot;10. 防重复提交与业务校验&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>按钮级防重复：<code>MultiuseButton</code> 通过 <code>ajaxing</code> 状态 + <code>sleep(200)</code> 防抖</li><li>业务层重复校验：如配件订购的 <code>checkRepeatPartList</code> 校验重复件</li><li>异常件限制：<code>preErrorPartList</code>、<code>showPartExistsOrderDialog</code> 等复杂分支</li><li>多步骤提交流程中的状态管理与回滚</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>clickHandler</code> 中 <code>ajaxing = true</code>，<code>await this.click()</code> 后 <code>ajaxing = false</code></li><li><code>isDisabled = ajaxing || disabled</code> 控制按钮不可用</li><li>业务侧需区分「继续提交」「取消」等用户选择，并串联后续校验逻辑</li></ul><hr><h3 id="_11-websocket-实时通知" tabindex="-1">11. WebSocket 实时通知 <a class="header-anchor" href="#_11-websocket-实时通知" aria-label="Permalink to &quot;11. WebSocket 实时通知&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>需与后端 WebSocket 服务建立长连接（<code>sockectNew.js</code>）</li><li>连接状态管理（<code>isOpen</code>）、重连、心跳等</li><li>与 Vuex 集成，消息需驱动全局通知（如 <code>createPromotionNotify</code>）</li><li>多 Tab 场景下消息处理的归属与去重</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>ConnectWebsocket</code> 封装连接逻辑，<code>getWSUrl</code> 从配置或 session 获取地址</li><li>消息到达后通过 Vuex action 更新状态，触发 UI 展示</li></ul><hr><h3 id="_12-多环境与微服务代理" tabindex="-1">12. 多环境与微服务代理 <a class="header-anchor" href="#_12-多环境与微服务代理" aria-label="Permalink to &quot;12. 多环境与微服务代理&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li>开发环境需配置大量 <code>proxyTable</code>（<code>/clouddms</code>、<code>/dms.part</code>、<code>/dms.claim</code> 等）</li><li>各服务独立部署，地址可能随环境变化</li><li>需区分 development / test / production，<code>config.serverUrl</code> 等动态切换</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>config/index.js</code> 中 <code>proxyTable</code> 按服务拆分</li><li><code>pathRewrite</code> 统一前缀，<code>changeOrigin</code> 解决跨域</li><li><code>.env</code>、<code>dotenv-webpack</code> 管理环境变量</li></ul><hr><h3 id="_13-打印功能" tabindex="-1">13. 打印功能 <a class="header-anchor" href="#_13-打印功能" aria-label="Permalink to &quot;13. 打印功能&quot;">​</a></h3><p><strong>难点描述</strong>：</p><ul><li><strong>多端适配</strong>：PC 端 Lodop 控件、非插件浏览器 CLodop 云打印、移动端/平板 C-Lodop、纯浏览器 <code>window.print</code></li><li><strong>Lodop vs CLodop</strong>：<code>needCLodop()</code> 根据 UA 判断（Chrome 41+、Firefox 41+、Edge、移动端等需 CLodop），旧版 IE 用 ActiveX 插件</li><li><strong>模板动态加载</strong>：<code>BasePrint</code> 按 <code>template</code> 从 <code>printTemplate/</code> 动态 <code>require</code> 打印模板组件</li><li><strong>样式与分页</strong>：Vue 的 <code>break-after: page</code> 需替换为 <code>page-break-after: always</code>；全局 style 注入</li><li><strong>WebPrint（PDF）</strong>：PDF 通过 iframe + PDF.js 预览打印；IE 用 <code>/static/webPrint/pdf/web/viewer.html?file=</code></li><li><strong>打印配置服务</strong>：<code>configPrint</code> 接口管理打印机列表、类型，支持远程打印服务</li></ul><p><strong>实现要点</strong>：</p><ul><li><code>getLodop()</code>：双端口 8000/18000 加载 CLodop，未安装时提示下载 <code>install_lodop32/64.exe</code>、<code>CLodop_Setup_for_Win32NT.exe</code></li><li><code>BasePrint</code>：<code>printerType</code>(laser/针打)、<code>direction</code>(vertical/horizontal)、<code>alwaysPrint</code>(连续纸)、<code>printCopies</code>、<code>ifPrintPreview</code>(直接打印/预览)</li><li><code>createPrintLogo</code>：表头注入经销商 logo、名称</li><li><code>$print(dom)</code> 插件：将 DOM 克隆到 iframe，处理 input/textarea/select 状态，<code>execCommand(&#39;print&#39;)</code> 或 <code>window.print()</code></li><li><code>clodopPad.js</code>：Pad 端走 HTTPS C-Lodop 服务（如 8443 端口）</li><li>独立打印页：<code>/print</code>、<code>/printPre</code>、<code>/appReceptionPrint</code>、<code>/balanceApp</code> 等在 <code>whiteList</code>，供移动 App 或外链直接打开</li></ul><p><strong>打印模板体系</strong>：</p><ul><li>维修工单、预检单、结算单、索赔单、配件出入库单、工具借还单、领料单等 30+ 业务模板</li><li>模板统一放在 <code>printTemplate/</code>，通过 <code>data</code>、<code>fileAddress</code>、<code>updateDate</code> 等 props 传参</li></ul><hr><h2 id="三、业务复杂度相关" tabindex="-1">三、业务复杂度相关 <a class="header-anchor" href="#三、业务复杂度相关" aria-label="Permalink to &quot;三、业务复杂度相关&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>复杂度说明</th></tr></thead><tbody><tr><td>维修接待</td><td>多 Tab、配件建议、工单打印、Lodop 打印集成</td></tr><tr><td>配件订购</td><td>购物车、重复件校验、异常件限制、ETKA iframe 集成</td></tr><tr><td>索赔管理</td><td>预索赔、三包、QA 等多子业务，流程分支多</td></tr><tr><td>结算</td><td>工单结算、索赔结算、败诉结算等，数据结构复杂</td></tr><tr><td>报表</td><td>ECharts 图表、多维度筛选、Excel 导出</td></tr><tr><td><strong>打印</strong></td><td><strong>BasePrint(Lodop) / WebPrint(PDF) / $print(DOM) / CLodop 云打印 / Pad 端 C-Lodop；30+ 业务模板；打印机配置服务</strong></td></tr></tbody></table><hr><h2 id="四、面试可展开的技术点" tabindex="-1">四、面试可展开的技术点 <a class="header-anchor" href="#四、面试可展开的技术点" aria-label="Permalink to &quot;四、面试可展开的技术点&quot;">​</a></h2><ol><li><p><strong>如何设计并实现前后端 API 签名机制？</strong><br> → 参数升序、MD5、密钥解密、GET/POST 差异化处理</p></li><li><p><strong>Vue 中如何实现多级菜单的递归渲染与权限控制？</strong><br> → 树形数据、递归组件、路由守卫、<code>formateMenu</code> 扁平化</p></li><li><p><strong>KeepAlive 缓存数量受限时如何处理？</strong><br> → maxCacheNum、动态 include、Tab 关闭时 remove、iframe 单独管理</p></li><li><p><strong>虚拟滚动的核心原理是什么？</strong><br> → 可视区域计算、DOM 复用、transform 定位、动态高度累加</p></li><li><p><strong>大型 Vue 项目的构建优化有哪些？</strong><br> → splitChunks、按需加载、内存限制、sourceMap 策略</p></li><li><p><strong>如何安全地与 iframe 内第三方页面通信？</strong><br> → postMessage、token 传递、targetOrigin 限制、生命周期清理</p></li><li><p><strong>企业级打印方案如何适配 PC、移动端、无插件浏览器？</strong><br> → Lodop 控件、CLodop 云打印、needCLodop 判断、Pad HTTPS 服务、$print 纯浏览器方案、PDF iframe 打印</p></li></ol><hr><h2 id="五、总结" tabindex="-1">五、总结 <a class="header-anchor" href="#五、总结" aria-label="Permalink to &quot;五、总结&quot;">​</a></h2><p>本项目综合了 <strong>企业级权限、API 安全、大型表格、虚拟滚动、多 Tab 缓存、iframe 集成、多端打印、构建优化</strong> 等前端常见难点，适合在面试中结合实际模块展开说明解决方案与个人贡献。</p>',96)]))}const g=o(t,[["render",l]]);export{h as __pageData,g as default};
